import React from "react";
import { SectionLabel, sectionTitle } from "./Skills";

export default function Contact({ contact }) {
  const items = [
    { icon: "✉", label: "Email", value: contact.email, href: `mailto:${contact.email}` },
    { icon: "📞", label: "Phone", value: contact.phone, href: `tel:${contact.phone}` },
    { icon: "in", label: "LinkedIn", value: contact.linkedin, href: contact.linkedinUrl },
    { icon: "📍", label: "Location", value: contact.location, href: null },
  ];

  return (
    <>
      <style>{`
        .contact-section {
          padding: clamp(2.5rem, 6vw, 5rem) clamp(1.25rem, 5vw, 4rem);
          text-align: center;
        }
        .contact-grid {
          display: grid;
          grid-template-columns: repeat(4, 1fr);
          gap: 0.9rem;
          max-width: 820px;
          margin: 0 auto 2rem;
        }
        .contact-card {
          background: var(--surface);
          border: 1px solid var(--border);
          border-radius: var(--radius);
          padding: clamp(0.9rem, 2.5vw, 1.4rem) clamp(0.75rem, 1.5vw, 1rem);
          display: flex;
          flex-direction: column;
          gap: 6px;
          transition: border-color 0.2s, transform 0.2s;
          text-decoration: none;
          text-align: left;
        }
        .contact-card.clickable:hover {
          border-color: var(--accent);
          transform: translateY(-3px);
        }
        .contact-icon { font-size: clamp(1rem, 2vw, 1.3rem); }
        .contact-lbl {
          font-size: clamp(0.62rem, 0.9vw, 0.7rem);
          color: var(--muted);
          font-family: var(--font-display);
          font-weight: 700;
          letter-spacing: 0.1em;
          text-transform: uppercase;
        }
        .contact-val {
          font-size: clamp(0.73rem, 1.1vw, 0.82rem);
          color: var(--text);
          font-weight: 500;
          word-break: break-all;
          line-height: 1.4;
        }
        .contact-cta {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          background: linear-gradient(135deg, var(--accent), var(--accent2));
          color: #fff;
          padding: clamp(10px, 2vw, 14px) clamp(24px, 4vw, 36px);
          border-radius: 99px;
          font-family: var(--font-display);
          font-weight: 700;
          font-size: clamp(0.85rem, 1.5vw, 1rem);
          letter-spacing: 0.02em;
          transition: opacity 0.2s, transform 0.2s;
          text-decoration: none;
        }
        .contact-cta:hover { opacity: 0.85; transform: scale(1.03); }
        .footer-txt {
          color: var(--muted);
          font-size: clamp(0.7rem, 1vw, 0.8rem);
          margin-top: 3rem;
        }

        @media (max-width: 820px) {
          .contact-grid { grid-template-columns: repeat(2, 1fr); max-width: 100%; }
        }
        @media (max-width: 440px) {
          .contact-grid { grid-template-columns: 1fr 1fr; }
          .contact-card { padding: 0.9rem 0.75rem; }
        }
      `}</style>

      <section className="contact-section" id="contact">
        <SectionLabel text="Contact" />
        <h2 style={{ ...sectionTitle, textAlign: "center" }}>Let's Build Something</h2>
        <p style={{ color: "var(--muted)", marginBottom: "2rem", maxWidth: 440, margin: "0 auto 2rem", fontSize: "clamp(0.85rem, 1.4vw, 0.98rem)" }}>
          Available for full-time roles and exciting fintech / enterprise projects.
        </p>

        <div className="contact-grid">
          {items.map((item, i) => (
            <a key={i} href={item.href || undefined}
              target={item.href?.startsWith("http") ? "_blank" : undefined}
              rel="noreferrer"
              className={`contact-card${item.href ? " clickable" : ""}`}
              style={{ color: "inherit" }}
            >
              <span className="contact-icon">{item.icon}</span>
              <span className="contact-lbl">{item.label}</span>
              <span className="contact-val">{item.value}</span>
            </a>
          ))}
        </div>

        <a href="mailto:chavanak870@gmail.com" className="contact-cta">✉ Send Email</a>

        <div className="footer-txt">
          Built with React · Designed to impress · © {new Date().getFullYear()} Akash Chavan
        </div>
      </section>
    </>
  );
}
